import React, { useState, useEffect } from "react";
import { Chessboard } from "react-chessboard";
import { Chess } from "chess.js";
import "./App.css";

const errorSound = new Audio("/error.mp3");

function App() {
  const [game, setGame] = useState(new Chess());
  const [fen, setFen] = useState(game.fen());
  const [gameOver, setGameOver] = useState(false);
  const [boardHighlight, setBoardHighlight] = useState("");

  useEffect(() => {
    if (game.isCheckmate()) {
      setGameOver(true);
      setBoardHighlight("checkmate");
    } else if (game.isStalemate()) {
      setGameOver(true);
      setBoardHighlight("stalemate");
    } else {
      setGameOver(false);
      setBoardHighlight("");
    }
  }, [fen, game]);

  const onDrop = (sourceSquare, targetSquare) => {
    try {
      const move = game.move({ from: sourceSquare, to: targetSquare, promotion: "q" });
      if (move === null) {
        errorSound.play();
        return false;
      }
      setFen(game.fen());
      setGame(new Chess(game.fen()));
      return true;
    } catch (e) {
      errorSound.play();
      return false;
    }
  };

  return (
    <div className={`app-container ${boardHighlight}`}>
      <h1>Chess Engine</h1>
      <div className={`chessboard-wrapper ${boardHighlight}`}>
        <Chessboard
          position={fen}
          onPieceDrop={onDrop}
          boardWidth={500}
          animationDuration={200}
        />
      </div>
      {gameOver && (
        <div className="game-over-message">
          <h2>{boardHighlight === "checkmate" ? "Checkmate!" : "Stalemate!"}</h2>
          <p>Game Over</p>
        </div>
      )}
    </div>
  );
}

export default App;
